# {The new algorithm adjusts edge distances by directly evaluating the contribution of each edge to local optima tours, altering distances to enhance routes containing frequently used edges while diversifying less optimal paths.}

def update_edge_distance(edge_distance, local_opt_tours, edge_n_used):
    updated_edge_distance = np.copy(edge_distance)
    rows, cols = edge_n_used.shape

    # Compute a new adjustment factor for each edge based on its usage in optimal tours
    for i in range(rows):
        for j in range(cols):
            if edge_n_used[i, j] > 0:
                if (i, j) in local_opt_tours:
                    # Reduce distance if frequently used in local optima tours to further enhance the route
                    updated_edge_distance[i, j] *= 0.9
                else:
                    # Increase distance if not part of optimal tour, promoting exploration
                    updated_edge_distance[i, j] *= 1.1

