import numpy as np

# {The new algorithm updates edge distances by applying a linear penalty to frequently used edges and a reward to underused edges, promoting exploration while avoiding short-term bias.}

def update_edge_distance(edge_distance, local_opt_tours, edge_n_used):
    # Parameters for linear adjustment
    penalty_factor = 0.1   # Penalty for frequently used edges
    reward_factor = 0.1    # Reward for underused edges

    updated_edge_distance = np.copy(edge_distance)
    rows, cols = edge_n_used.shape

    # Compute usage frequency adjustments
    for i in range(rows):
        for j in range(cols):
            if edge_n_used[i, j] > 0:
                # Apply a higher distance penalty for frequently used edges
                updated_edge_distance[i, j] += penalty_factor * edge_n_used[i, j]
            else:
                # Reward underused edges by reducing their distance
                updated_edge_distance[i, j] -= reward_factor

    # Ensure no negative distances
    updated_edge_distance = np.maximum(updated_edge_distance, 0)

    return updated_edge_distance

import numpy as np

# {The new algorithm redistributes edge distances by applying a quadratic scaling based on the inverse of deviation from mean usage frequency, strengthening attributes of both frequently and infrequently used edges.}

def update_edge_distance(edge_distance, local_opt_tours, edge_n_used):
    mean_usage = np.mean(edge_n_used)
    usage_range = np.max(edge_n_used) - np.min(edge_n_used)

    quadratic_factor = 0.1

    updated_edge_distance = np.copy(edge_distance)

    for i in range(edge_distance.shape[0]):
        for j in range(edge_distance.shape[1]):
            usage_deviation = (mean_usage - edge_n_used[i, j]) / (usage_range + 1e-5)
            scaling_factor = quadratic_factor * (1 + usage_deviation**2)

            if edge_n_used[i, j] < mean_usage:
                reduction_value = scaling_factor * (mean_usage - edge_n_used[i, j])
                updated_edge_distance[i, j] = max(0, updated_edge_distance[i, j] - reduction_value)
            else:
                increase_value = scaling_factor * (edge_n_used[i, j] - mean_usage)
                updated_edge_distance[i, j] += increase_value

    return updated_edge_distance

import numpy as np

# {The new algorithm modifies edge distances using a logarithmic decay based on historical usage frequency, giving a stronger penalty to more frequently used edges to encourage diversification.}

def update_edge_distance(edge_distance, local_opt_tours, edge_n_used):
    # Parameters for logarithmic decay
    decay_factor = 2.0  # Logarithmic decay for frequent edges

    updated_edge_distance = np.copy(edge_distance)
    rows, cols = edge_n_used.shape

    # Compute usage frequency adjustments
    frequency_adjustment = np.zeros((rows, cols))
    for i in range(rows):
        for j in range(cols):
            if edge_n_used[i, j] > 0:
                frequency_adjustment[i, j] = np.log(1 + decay_factor * edge_n_used[i, j])
                updated_edge_distance[i, j] *= (1 + frequency_adjustment[i, j])

    return updated_edge_distance
